module shift_register(CLK, RST, LOAD, D, Q);
input CLK, RST, LOAD;
input [3:0] D;
output reg [3:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST)
        Q <= 4'b0000;
    else begin
        if (LOAD)
            Q <= D;
        else
            Q <= {1'b0, Q[3:1]};
    end
end

endmodule
